import pygame
import sys
import random

# Initialize Pygame
pygame.init()

# Set up some constants
WIDTH, HEIGHT = 800, 600
WHITE = (255, 255, 255)
RED = (255, 0, 0)
BLACK = (0, 0, 0)
FONT = pygame.font.SysFont("Arial", 24)

class Game:
    def __init__(self):
        self.screen = pygame.display.set_mode((WIDTH, HEIGHT))
        self.clock = pygame.time.Clock()
        self.score = 0
        self.game_over = False
        self.player = pygame.Rect(WIDTH / 2, HEIGHT / 2, 50, 50)
        self.enemies = [pygame.Rect(random.randint(0, WIDTH), random.randint(0, HEIGHT), 50, 50) for _ in range(10)]

    def handle_events(self):
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                pygame.quit()
                sys.exit()
            if event.type == pygame.KEYDOWN:
                if event.key == pygame.K_r and self.game_over:
                    self.game_over = False
                    self.score = 0
                    self.player = pygame.Rect(WIDTH / 2, HEIGHT / 2, 50, 50)
                    self.enemies = [pygame.Rect(random.randint(0, WIDTH), random.randint(0, HEIGHT), 50, 50) for _ in range(10)]

    def update(self):
        if not self.game_over:
            keys = pygame.key.get_pressed()
            if keys[pygame.K_UP]:
                self.player.y -= 5
            if keys[pygame.K_DOWN]:
                self.player.y += 5
            if keys[pygame.K_LEFT]:
                self.player.x -= 5
            if keys[pygame.K_RIGHT]:
                self.player.x += 5

            for enemy in self.enemies:
                if self.player.colliderect(enemy):
                    self.game_over = True

            self.score += 1 / 60

    def render(self):
        self.screen.fill(BLACK)
        if self.game_over:
            text = FONT.render("Game Over! Press R to restart", True, WHITE)
            self.screen.blit(text, (WIDTH / 2 - text.get_width() / 2, HEIGHT / 2 - text.get_height() / 2))
        else:
            pygame.draw.rect(self.screen, WHITE, self.player)
            for enemy in self.enemies:
                pygame.draw.rect(self.screen, RED, enemy)
            text = FONT.render(f"Score: {int(self.score)}", True, WHITE)
            self.screen.blit(text, (10, 10))
        pygame.display.flip()

    def run(self):
        while True:
            self.handle_events()
            self.update()
            self.render()
            self.clock.tick(60)

if __name__ == "__main__":
    game = Game()
    game.run()
